# Category: cicd_security

pipeline {
    agent any

    environment {
        DEPLOY_USER = 'deploy'
        TARGET_HOSTS = 'prod1.example.com prod2.example.com'
        APP_DIR = '/opt/myapp'
        ARTIFACT = 'build/myapp.tar.gz'
    }

    options {
        timestamps()
    }

    stages {
        stage('Checkout') {
            steps {
                checkout scm
            }
        }

        stage('Build') {
            steps {
                sh '''
                    set -e
                    mkdir -p build
                    tar -czf ${ARTIFACT} .
                '''
            }
        }

        stage('Deploy to Production') {
            steps {
                script {
                    def hosts = env.TARGET_HOSTS.split(' ')
                    withCredentials([usernamePassword(credentialsId: 'prod-deploy-creds', usernameVariable: 'DEPLOY_USER', passwordVariable: 'DEPLOY_PASS')]) {
                        for (h in hosts) {
                            sh """
                                set -e
                                sshpass -p "$DEPLOY_PASS" scp -o StrictHostKeyChecking=no ${ARTIFACT} ${DEPLOY_USER}@${h}:/tmp/myapp.tar.gz
                                sshpass -p "$DEPLOY_PASS" ssh -o StrictHostKeyChecking=no ${DEPLOY_USER}@${h} '
                                    set -e
                                    mkdir -p ${APP_DIR}
                                    tar -xzf /tmp/myapp.tar.gz -C ${APP_DIR}
                                    rm -f /tmp/myapp.tar.gz
                                    sudo systemctl restart myapp
                                '
                            """
                        }
                    }
                }
            }
        }
    }

    post {
        success {
            echo 'Production deployment completed successfully.'
        }
